const profiles={hu:[{max:7,k:'Nyitott felfedező',t:'Digitális felfedező',d:'Kíváncsian használod a digitális eszközöket, de nem minden alkalmazás része a napjaidnak.',type:'explorer'},{max:11,k:'Kapcsolódó',t:'Digitális kapcsolattartó',d:'A digitális világ főleg a kapcsolattartásban, tanulásban és hétköznapi ügyekben segít neked.',type:'connector'},{max:15,k:'Sokoldalú használó',t:'Digitális mindenes',d:'Többféle platformon vagy aktív: kommunikálsz, tanulsz, szórakozol és alkotsz is.',type:'creator'},{max:99,k:'Intenzív használó',t:'Digitális szuperhasználó',d:'A digitális világ szinte minden területét használod – a közösségi médiától az AI-ig.',type:'power'}],en:[{max:7,k:'Open explorer',t:'Digital explorer',d:'You use digital tools with curiosity, but not every app is part of your everyday life.',type:'explorer'},{max:11,k:'Connected user',t:'Digital connector',d:'The digital world mainly helps you communicate, learn and manage everyday tasks.',type:'connector'},{max:15,k:'Versatile user',t:'Digital all-rounder',d:'You are active across several platforms: communicating, learning, relaxing and creating.',type:'creator'},{max:99,k:'Intensive user',t:'Digital power user',d:'You use almost every part of the digital world – from social media to AI.',type:'power'}]};
const profileQuestions={hu:[{q:'Naponta körülbelül mennyi időt töltesz online?',a:[['0–1 óra',1],['1–3 óra',2],['3–6 óra',3],['6+ óra',4]]},{q:'Melyik tevékenység jellemző rád leginkább?',a:[['Chat és üzenetek',1],['Közösségi média',2],['Videó és streaming',3],['Játék vagy alkotás',3]]},{q:'Milyen gyakran nézel rövid videókat?',a:[['Ritkán',1],['Naponta néhányszor',2],['Sokszor egy nap',3],['Szinte folyamatosan',4]]},{q:'Milyen gyakran használsz AI-t?',a:[['Még nem használom',1],['Hetente',2],['Naponta',3],['Naponta többször',4]]},{q:'Hány digitális eszközt használsz rendszeresen?',a:[['1',1],['2',2],['3',3],['4 vagy több',4]]}],en:[{q:'About how much time do you spend online each day?',a:[['0–1 hour',1],['1–3 hours',2],['3–6 hours',3],['6+ hours',4]]},{q:'Which activity describes you best?',a:[['Chat and messages',1],['Social media',2],['Video and streaming',3],['Gaming or creating',3]]},{q:'How often do you watch short videos?',a:[['Rarely',1],['A few times a day',2],['Many times a day',3],['Almost constantly',4]]},{q:'How often do you use AI?',a:[['Not yet',1],['Weekly',2],['Daily',3],['Several times a day',4]]},{q:'How many digital devices do you use regularly?',a:[['1',1],['2',2],['3',3],['4 or more',4]]}]};
const impacts={hu:[{id:'email',group:1,icon:'✉️',title:'1 rövid e-mail',short:'néhány KB · ≈0,3 g CO₂e',detail:'Egy néhány soros, csatolmány nélküli e-mail fájlmérete jellemzően csak néhány kilobájt, míg a csatolmány több tíz megabájtra növelheti. Egy széles körben idézett becslés a rövid e-mailt kb. 0,3 g, a nagy csatolmányos e-mailt akár 50 g CO₂e-re teszi. Világszerte naponta közel 400 milliárd e-mailt küldünk és fogadunk. [2][12]'},{id:'web',group:2,icon:'🌐',title:'1 weboldal megnyitása',short:'tipikusan ≈3 MB · átlagosan ≈0,36 g CO₂e',detail:'A medián asztali weboldal 2026-ban körülbelül 3 MB adatot tölt le. A Website Carbon Calculator globális átlagként kb. 0,36 g CO₂e-t becsül egy oldalmegtekintésre; a konkrét érték az oldal méretétől, az eszköztől, a hálózattól és az árammixtől függ. [8][16]'},{id:'photo',group:2,icon:'📷',title:'1 kép közzététele Instagramon',short:'≈0,8 MB · ≈0,15 g CO₂e',detail:'A Greenspector vizsgálatában egy fénykép Instagram-feedbe történő közzététele 0,806 MB adatforgalommal és 0,154 g CO₂e becsült hatással járt. A kép mérete és a platform működése ezt jelentősen módosíthatja. [13]'},{id:'feed',group:3,icon:'📱',title:'1 óra TikTok-görgetés',short:'több száz MB · ≈58 g CO₂e',detail:'A TikTok a videókat előre is betölti: a Greenspector mérésében az indulás utáni 30 másodpercben kb. 5 MB adat mozgott, a görgetés becsült hatása pedig 0,96 g CO₂e/perc volt, ami egy órára vetítve kb. 58 g. [13]'},{id:'call',group:3,icon:'📹',title:'1 óra videóhívás',short:'≈1,1 GB · 10–22 g CO₂e',detail:'Egy 2026-os mobilhálózati mérés kamerával átlagosan 18,07 MB/perc, vagyis kb. 1,08 GB/óra adatforgalmat talált. A becsült kibocsátás 10,2–21,6 g CO₂e/óra volt; Wi-Fi-n és más árammix mellett eltérhet. [15]'},{id:'stream',group:3,icon:'🎬',title:'1 óra streaming',short:'≈0,3–7 GB · központi becslés ≈36 g CO₂e',detail:'A Netflix szerint az adatforgalom az alacsony minőségű 0,3 GB/órától a 4K 7 GB/óráig terjedhet. Az IEA központi becslése egy óra streamingre 36 g CO₂e, de az eszköz, a felbontás, a hálózat és az árammix sokat számít. [9][14]'}],en:[{id:'email',group:1,icon:'✉️',title:'1 short email',short:'a few KB · ≈0.3 g CO₂e',detail:'A short email without an attachment is usually only a few kilobytes, while attachments can raise it to tens of megabytes. A widely cited estimate puts a short email at about 0.3 g and a large attached email at up to 50 g CO₂e. Nearly 400 billion emails are sent and received worldwide every day. [2][12]'},{id:'web',group:2,icon:'🌐',title:'1 web page view',short:'typically ≈3 MB · global average ≈0.36 g CO₂e',detail:'The median desktop page transfers about 3 MB. Website Carbon estimates a global average of about 0.36 g CO₂e per page view; the actual value depends on page size, device, network and electricity mix. [8][16]'},{id:'photo',group:2,icon:'📷',title:'1 Instagram photo post',short:'≈0.8 MB · ≈0.15 g CO₂e',detail:'In Greenspector’s test, publishing a photo to an Instagram feed transferred 0.806 MB and had an estimated impact of 0.154 g CO₂e. Image size and platform behaviour can change this significantly. [13]'},{id:'feed',group:3,icon:'📱',title:'1 hour of TikTok scrolling',short:'hundreds of MB · ≈58 g CO₂e',detail:'TikTok preloads video: Greenspector measured about 5 MB in the first 30 seconds after launch and 0.96 g CO₂e per minute of scrolling, equivalent to about 58 g per hour. [13]'},{id:'call',group:3,icon:'📹',title:'1 hour video call',short:'≈1.1 GB · 10–22 g CO₂e',detail:'A 2026 mobile-network experiment measured 18.07 MB/minute with the camera on, about 1.08 GB/hour. Estimated emissions were 10.2–21.6 g CO₂e/hour; Wi-Fi and other electricity mixes will differ. [15]'},{id:'stream',group:3,icon:'🎬',title:'1 hour streaming',short:'≈0.3–7 GB · central estimate ≈36 g CO₂e',detail:'Netflix states that data use ranges from 0.3 GB/hour at low quality to 7 GB/hour in 4K. The IEA central estimate is 36 g CO₂e for one hour, but device, resolution, network and electricity mix matter. [9][14]'}]};
const tips={hu:[{title:'Felhasználóként',icon:'👤',items:[['Kapcsold ki az automatikus lejátszást','Így nem indulnak el olyan videók, amelyeket nem is akarsz megnézni, és ezáltal felesleges adatforgalom és energiafelhasználás sem keletkezik. A videós és közösségi appok beállításaiban keresd az „Automatikus lejátszás”, „Adatforgalom” vagy „Adatkímélő mód” menüpontot.'],['Válassz megfelelő felbontást','Telefonon sokszor nincs szükség 4K vagy Full HD minőségre. Az alacsonyabb felbontás kevesebb adatot mozgat, ezért a hálózat és az eszköz is kevesebb energiát használhat. YouTube-on a fogaskerék alatt a Minőség, Netflixen a Fiók → Lejátszási beállítások menüben módosíthatod.'],['Használd tovább a jól működő eszközt','A telefon vagy laptop gyártásához nyersanyag és energia kell, ezért a hosszabb használat csökkenti az egy évre jutó gyártási környezeti hatást. Egy tok, akkucsere vagy javítás gyakran évekkel meghosszabbíthatja az eszköz életét.'],['Használd célzottan az AI-t','Fogalmazd meg egyszerre pontosan, mire van szükséged, így kevesebb felesleges újragenerálásra lehet szükség. Ha elég a szöveg, ne kérj képet vagy videót, mert ezek általában több számítást és energiát igényelnek.']]},{title:'Tartalomkészítőként',icon:'✏️',items:[['Méretezd a képet a felülethez','Egy 4000 pixeles fotót ne tölts fel, ha csak 800 pixel szélesen jelenik meg. A megfelelő méret kevesebb letöltendő adatot jelent, ezért gyorsabb lehet a betöltés és csökkenhet a szerver, a hálózat és a látogatói eszköz energiaigénye.'],['Használj modern képformátumot','A WebP vagy AVIF ugyanazt a látványt gyakran jóval kisebb fájlból adja, mint a JPEG vagy PNG. Így minden oldalmegtekintéskor kevesebb adatot kell továbbítani; a beépített Carbon.Crane-eszköz ezt automatikusan is elvégezheti.'],['Kerüld a felesleges háttérvideókat','Az automatikusan induló videó akkor is adatot mozgat és energiát használ, ha a látogató nem nézi. Használj állóképet vagy kattintásra induló videót, amikor az is elég.'],['Töltsd be később, ami nincs a képernyőn','A „lazy loading” csak akkor tölti le az alsó képeket és videókat, amikor a látogató közel ér hozzájuk. Ha valaki nem görget le odáig, az adatforgalom és az ahhoz kapcsolódó energiafelhasználás sem keletkezik.']]},{title:'Közösségként',icon:'🤝',items:[['Mérjétek meg az iskola weboldalát','Válasszatok néhány fontos oldalt, például a nyitóoldalt és a híreket. A mérés megmutatja az oldal méretét, becsült energia- és karbonlábnyomát, valamint azt, mely elemek csökkenthetők.'],['Kezdjétek a leglátogatottabb oldalakkal','A sokszor megnyitott oldalakon minden kis javítás újra és újra megtakarítást hoz. Ha egy oldal minden letöltése kisebb, akkor minden látogatónál kevesebb adatforgalom és energiahasználat keletkezik: itt működik legerősebben a domino effektus.'],['Küldjetek konkrét javaslatot','Ne csak azt írjátok, hogy „legyen zöldebb”. Mutassátok meg, mely képek nagyok, mennyivel csökkenthetők, és hogyan javulhat a betöltési sebesség, az energiahasználat és a felhasználói élmény.'],['Mérjetek újra a változtatás után','Az előtte–utána mérés számszerűen megmutatja, mennyivel lett kisebb az oldal, és hogyan változott az egy oldalmegtekintésre jutó energia- és karbonérték. Ezt meg lehet osztani az iskolai közösséggel is.']]}],en:[{title:'As a user',icon:'👤',items:[['Turn off autoplay','This stops videos you never intended to watch, so the associated data transfer and energy use do not occur. Look for “Autoplay”, “Data usage” or “Data saver” in video and social app settings.'],['Choose the right resolution','On a phone you often do not need 4K or Full HD. Lower resolution transfers less data, so the network and device may use less energy. On YouTube use Settings → Quality; on Netflix use Account → Playback settings.'],['Keep a working device longer','Making a phone or laptop requires materials and energy, so keeping it longer reduces the manufacturing impact allocated to each year of use. A case, battery replacement or repair can often extend its life by years.'],['Use AI with a clear purpose','Describe what you need accurately in one prompt so fewer unnecessary regenerations are needed. When text is enough, do not generate an image or video, as these usually require more computing and energy.']]},{title:'As a creator',icon:'✏️',items:[['Resize images for the screen','Do not upload a 4,000-pixel photo if it appears at only 800 pixels wide. The right size means less data to download, faster loading and lower energy demand across the server, network and visitor device.'],['Use a modern image format','WebP or AVIF can often deliver the same visual result with a much smaller file than JPEG or PNG. Less data is transferred on every page view; the embedded Carbon.Crane tool can automate this.'],['Avoid unnecessary background video','An autoplaying video transfers data and uses energy even when the visitor is not watching. Use a still image or click-to-play video when that is enough.'],['Load off-screen content later','Lazy loading downloads lower-page images and video only when the visitor approaches them. If the visitor never scrolls that far, the data transfer and associated energy use do not occur.']]},{title:'As a community',icon:'🤝',items:[['Measure your school website','Choose important pages such as the homepage and news section. Measurement shows page size, estimated energy and carbon footprint, and which elements can be reduced.'],['Start with the most-visited pages','Every small improvement on a popular page saves data repeatedly. When each page load is smaller, every visitor causes less data transfer and energy use: this is where the domino effect is strongest.'],['Send a concrete recommendation','Do not just say “make it greener”. Show which images are large, how much they could shrink, and how loading speed, energy use and user experience could improve.'],['Measure again after changes','A before-and-after measurement quantifies how much smaller the page became and how energy and carbon per page view changed. Share the result with the school community.']]}]};
const videoScripts={hu:{definition:{title:'Mi az a digitális karbonlábnyom?',text:'A digitális világ láthatatlannak tűnik, de valódi gépek működtetik. Amikor üzenetet küldesz, videót nézel vagy AI-t használsz, szerverek számolnak, adatok utaznak, az eszközöd pedig energiát használ. Az ehhez kapcsolódó kibocsátást nevezzük digitális karbonlábnyomnak. Nézzük meg, mekkora lett ez a világ!'},why:{title:'Miért nő a digitális világ hatása?',text:'A digitalizáció sok mindent egyszerűbbé tett: kevesebb papírt használunk, és utazás nélkül intézhetünk ügyeket. Közben viszont egyre több videót, alkalmazást és online szolgáltatást használunk. Több gép, több adatközpont, több energia és hűtés kell. A jó hír: a hatékonyabb digitális megoldás gyakran gyorsabb és jobb is.'},click:{title:'Mi történik egy kattintás mögött?',text:'Amikor megnyitsz egy oldalt, a tartalom általában nem a telefonodon vár. Egy adatközpont szerveréről indul, kábeleken, routereken, Wi-Fi-n vagy mobilhálózaton utazik, majd megjelenik az eszközödön. Minél több adat érkezik, annál több munkát végez a teljes útvonal.'},impact:{title:'Nem minden digitális tartalom egyforma',text:'Egy rövid szöveges e-mail általában csak kevés adat. Egy weboldal már megabájtokat, egy órányi videó pedig akár gigabájtokat is mozgathat. A pontos érték mindig függ a minőségtől és a szolgáltatástól. A lényeg: amit kisebbre tervezünk, azt kevesebb adatból is el lehet juttatni hozzád.'},ai:{title:'AI, energia és víz',text:'Az AI nem a telefonodban gondolkodik egyedül. Nagy teljesítményű szerverek végeznek rengeteg számítást adatközpontokban. Ehhez áram kell, a keletkező hőt pedig el kell vezetni. Egyes hűtési rendszerek vizet is használnak. Ezért számít, hogy az AI-t milyen feladatra és milyen gyakran használjuk.'},method:{title:'A domino effektus',text:'Ha egy weboldal képét kisebbre optimalizálják, kevesebb adatot kell tárolni, továbbítani és feldolgozni. A szerver, a hálózat és a te eszközöd is kevesebbet dolgozik. Egyetlen fejlesztői döntés így minden látogatásnál újra csökkentheti az energiahasználatot. Ez a digitális domino effektus.'}},en:{definition:{title:'What is a digital carbon footprint?',text:'The digital world may look invisible, but real machines keep it running. When you send a message, watch a video or use AI, servers calculate, data travels and your device uses energy. The emissions linked to all of this make up the digital carbon footprint. Let’s see how large this world has become.'},why:{title:'Why is the impact growing?',text:'Digitalisation has made many things easier: we use less paper and can manage tasks without travelling. But we also use more video, apps and online services. That means more machines, data centres, electricity and cooling. The good news is that a more efficient digital service is often faster and better too.'},click:{title:'What happens behind a click?',text:'When you open a page, the content is usually not waiting on your phone. It starts on a server in a data centre, travels through cables, routers, Wi-Fi or a mobile network, and appears on your device. The more data that arrives, the more work the whole route must do.'},impact:{title:'Digital content is not all the same',text:'A short text email usually moves little data. A web page transfers megabytes, while an hour of video may transfer gigabytes. The exact amount depends on quality and service. The key idea is simple: when content is designed to be smaller, it can reach you using less data.'},ai:{title:'AI, energy and water',text:'AI is not thinking inside your phone by itself. Powerful servers carry out huge numbers of calculations in data centres. They need electricity, and the heat they create must be removed. Some cooling systems also use water. That is why it matters what we use AI for and how often.'},method:{title:'The domino effect',text:'When a website image is optimised, less data needs to be stored, transferred and processed. The server, network and your device all do less work. One developer decision can therefore reduce energy use every time someone visits. This is the digital domino effect.'}}};
const quiz={hu:[{q:'Mi a digitális karbonlábnyom?',a:['Csak az eszközök gyártásának hatása','A digitális eszközökhöz, adatátvitelhez és adatközpontokhoz kapcsolódó kibocsátás','Csak az adatközpontok vízhasználata'],c:1},{q:'Honnan érkezik a weboldal tartalma az eszközödre?',a:['Az adatközpont szerveréről, a hálózaton át','Csak a telefon memóriájából','A műholdról közvetlenül'],c:0},{q:'Mit jelent a „felhő”?',a:['Valódi szervereket és adatközpontokat','Egy különleges időjárási jelenséget','Csak vezeték nélküli kapcsolatot'],c:0},{q:'Miért kell hűteni az adatközpontokat?',a:['Mert a számítógépek hőt termelnek','Mert a fájlok megfagynak','Csak a dolgozók miatt'],c:0},{q:'Mi a domino effektus?',a:['Ha egy oldal kisebb lesz, a látogatóknál is csökkenhet az energiaigény','Ha minden oldal bezár','Ha egymásra döntjük a szervereket'],c:0},{q:'Miért jó a képoptimalizálás?',a:['Ugyanaz az élmény kisebb fájlból is elérhető','Mindig rosszabb lesz a kép','Csak a fejlesztőnek jó'],c:0}],en:[{q:'What is a digital carbon footprint?',a:['Only the impact of manufacturing devices','Emissions linked to devices, data transfer and data centres','Only water used by data centres'],c:1},{q:'How does website content reach your device?',a:['From a data-centre server through the network','Only from the phone memory','Directly from a satellite'],c:0},{q:'What does “the cloud” mean?',a:['Real servers and data centres','A special weather event','Only a wireless connection'],c:0},{q:'Why do data centres need cooling?',a:['Computers produce heat','Files might freeze','Only for staff comfort'],c:0},{q:'What is the domino effect?',a:['A smaller page can also reduce energy use for visitors','Closing every page','Knocking servers over'],c:0},{q:'Why optimise images?',a:['The same experience can use a smaller file','The image always becomes worse','It only helps developers'],c:0}]};
