function tr(k){return copy[lang][k]||k} function format(n,dec=0){return new Intl.NumberFormat(lang==='hu'?'hu-HU':'en-US',{maximumFractionDigits:dec,minimumFractionDigits:dec}).format(n)}
function applyLanguage(){document.documentElement.lang=lang;$$('[data-i18n]').forEach(el=>{const v=copy[lang][el.dataset.i18n];if(v!==undefined)el.textContent=v});$$('.lang').forEach(b=>b.classList.toggle('active',b.dataset.lang===lang));$$('.count').forEach(el=>{el.dataset.suffix=lang==='hu'?(el.dataset.suffixHu??el.dataset.suffix??''):(el.dataset.suffixEn??el.dataset.suffix??'');const dec=+(el.dataset.decimals||0);el.textContent=format(+el.dataset.count,dec)+el.dataset.suffix});renderProfile(true);renderImpacts(false);renderTips();renderScripts();renderChallenges();renderImages();updateCounter();}
$$('.lang').forEach(b=>b.onclick=()=>{lang=b.dataset.lang;applyLanguage()});
function updateHeaderOffset(){document.documentElement.style.setProperty('--header-offset',`${$('#siteHeader').offsetHeight+14}px`)} window.addEventListener('resize',updateHeaderOffset);updateHeaderOffset();
function scrollToTarget(id){const target=document.getElementById(id);if(!target)return;const top=target.getBoundingClientRect().top+window.scrollY-$('#siteHeader').offsetHeight-12;window.scrollTo({top,behavior:'smooth'});history.replaceState(null,'',`#${id}`)}
$$('[data-scroll],[data-target]').forEach(b=>b.addEventListener('click',()=>{scrollToTarget(b.dataset.scroll||b.dataset.target);if(b.closest('.mobile-menu'))$('#mobileMenu').hidden=true}));$('#menuButton').onclick=()=>{const m=$('#mobileMenu');m.hidden=!m.hidden;$('#menuButton').setAttribute('aria-expanded',String(!m.hidden));updateHeaderOffset()};
const obs=new IntersectionObserver(entries=>entries.forEach(e=>{if(e.isIntersecting){$$('.step').forEach(s=>s.classList.toggle('active',s.dataset.target===e.target.id))}}),{rootMargin:'-35% 0px -55%'});$$('.observe-section').forEach(s=>obs.observe(s));
function animateCounts(){ $$('.count').forEach(el=>{const target=+el.dataset.count,dec=+(el.dataset.decimals||0),dur=900,start=performance.now();function tick(t){const p=Math.min(1,(t-start)/dur),v=target*(1-Math.pow(1-p,3));el.textContent=format(v,dec)+(el.dataset.suffix||'');if(p<1)requestAnimationFrame(tick)}requestAnimationFrame(tick)})} animateCounts();
