let impactOrder=[];function shuffle(a){return [...a].sort(()=>Math.random()-.5)}
function renderImpacts(randomize=true){if(randomize||!impactOrder.length)impactOrder=shuffle(impacts[lang]);else impactOrder=impactOrder.map(x=>impacts[lang].find(y=>y.id===x.id));const grid=$('#impactGrid');grid.innerHTML=impactOrder.map((x,i)=>`<article class="impact-card" draggable="true" data-id="${x.id}"><span class="icon">${x.icon}</span><strong>${x.title}</strong><small>${x.short}</small><div class="reorder-controls"><button aria-label="left" data-move="-1">←</button><button aria-label="right" data-move="1">→</button></div></article>`).join('');bindSort();$('#impactFeedback').hidden=true;$('#impactDetails').hidden=true}
function bindSort(){
  const grid=$('#impactGrid'); let dragged=null;
  $$('.impact-card',grid).forEach(card=>{
    card.addEventListener('dragstart',()=>{dragged=card;card.classList.add('dragging')});
    card.addEventListener('dragend',()=>{card.classList.remove('dragging');syncImpactOrder()});
    card.addEventListener('dragover',e=>{
      e.preventDefault(); if(!dragged||dragged===card)return;
      const box=card.getBoundingClientRect(); const before=e.clientX<box.left+box.width/2;
      grid.insertBefore(dragged,before?card:card.nextSibling);
    });
    $$('[data-move]',card).forEach(btn=>{
      btn.onclick=e=>{
        e.stopPropagation(); const dir=+btn.dataset.move,index=[...grid.children].indexOf(card),to=index+dir;
        if(to<0||to>=grid.children.length)return;
        dir<0?grid.insertBefore(card,grid.children[to]):grid.insertBefore(grid.children[to],card);
        syncImpactOrder();
      };
    });
  });
}
